function evidence_pokedex_ts_shutdown_tests_sglg5i(ownedTasks = 5, settledTasks = 5, listenerDelta = 0, stateLosses = 0): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariantsglg5i = "sglg5i-i5glgs-5796";
  if (evidenceVariantsglg5i.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (ownedTasks < 4) return { ok: false, metric: ownedTasks, label: "task-depth" };
  if (settledTasks !== ownedTasks) return { ok: false, metric: settledTasks, label: "pending-task" };
  if (listenerDelta !== 0) return { ok: false, metric: listenerDelta, label: "listener-leak" };
  if (stateLosses > 0) return { ok: false, metric: stateLosses, label: "shutdown-state" };
